syntax = "proto3";

package com.wechaten.protocol;

option java_package = "com.wechaten.protocol";
option java_outer_classname = "GameProtocol";

// WebSocket消息包装器 - 支持二进制数据
message WebSocketMessage {
    int64 requestId = 1;
    string service = 2;
    string method = 3;
    bool isSuccess = 4;  // 用于匹配请求和响应
    int64 timestamp = 5;
    bytes data = 6;  // 存储编码后的消息数据
}
// 用户个人信息
message User{
    int64 uuid = 1;
    string username = 2;
    string avatarUrl = 3;
}
// 脚本格式
message ChatScript{
    // 剧本标题
    string scene = 1;
    // 额外展示的剧本提示
    optional string tips =2;
    // 额外展示的图片链接
    optional string image =3;
    // 剧本内容
    repeated Conversation conversation = 4;
}
// 对话格式
message Conversation{
    // 发言者
    string speaker =1;
    // 对话内容的英标
    string pronunciation =2;
    // 对话英文内容
    string english =3;
    // 对话中文内容;
    string chinese = 4;
    // 语音消息链接
    optional string audioUrl =5;
    // 语音时长
    optional string audioDuration = 6;
}
// 发送的消息
message SpeakMessage{
    User selfUser = 1;
    User matchUser =2;
    string fromSpeaker =3;
    string audioUrl = 4;
    string audioDuration =5;
}
message SpeakMessageResponse{
    // 接下来是谁发言
    string nextSpeak = 1;
}
message ConversationResult{
    bool isConversationEnd = 1;
}
// 操作是否成功
message ResponseResult{
    bool isSuccess = 1;
}
// 退出房间
message ExitRoomRequest{
    User selfUser = 1;
    User matchUser =2;
}
// 催促对方
message HurryUpInfo{
    User fromUser =1;
    User toUser =2;
}
// 给对方点赞
message LikeInfo{
    User fromUser =1;
    User toUser =2;
}
// 请求STS临时凭证
message STSTokenRequest{
    User user = 1;  // 用户信息（用于追踪和审计）
}
// STS凭证响应
message STSTokenResponse{
    string accessKeyId = 1;      // 临时AccessKey ID
    string accessKeySecret = 2;  // 临时AccessKey Secret
    string securityToken = 3;     // 安全令牌
    string expiration = 4;       // 过期时间（ISO 8601格式）
    string region = 5;           // OSS区域
    string bucket = 6;           // OSS Bucket名称
    string endpoint = 7;         // OSS Endpoint
    // 表单直传相关字段（用于微信小程序等环境）
    optional string policy = 8;   // Post Policy（Base64编码）
    optional string signature = 9; // Post Policy签名（Base64编码）
}
// 请求服务接口
service GameProtocolService {
    
    // 匹配玩家
    rpc MatchUser(User) returns (ResponseResult);
    // 取消匹配玩家
    rpc CancelMatchUser(User) returns (ResponseResult);
    // 退出房间
    rpc ExitRoom(ExitRoomRequest) returns (ResponseResult);
    // 发送消息
    rpc SendMessage(SpeakMessage) returns (SpeakMessageResponse);
    // 催促对方
    rpc HurryUp(HurryUpInfo) returns (ResponseResult);
    // 给对方点赞
    rpc Like(LikeInfo) returns (ResponseResult);
    // 获取OSS上传STS临时凭证
    rpc GetSTSToken(STSTokenRequest) returns (STSTokenResponse);
}
